={{ 
(() => {
  const lista = $( "Listar Unidade Medida" ).all().map(i => i.json);
  const unidadeDaIA = $('When Executed by Another Workflow').first().json.unidade;
  const buscaIA = ( unidadeDaIA || "" ).toLowerCase().trim();

  // 1. Tenta encontrar uma correspondência exata (ex: "saca" === "saca")
  let encontrado = lista.find(item => 
    (item.translations?.pt || "").toLowerCase() === buscaIA
  );

  // 2. Se não achar exato, tenta o que começa com a palavra (ex: "saca" em "saca 60kg")
  if (!encontrado) {
    encontrado = lista.find(item => 
      (item.translations?.pt || "").toLowerCase().includes(buscaIA)
    );
  }

  if (!encontrado) {
    throw new Error(`Unidade '${unidadeDaIA}' não encontrada.`);
  }

  return encontrado.id; 
})()
}}

